import { generatePriceData, generateTimeLabels, rnd } from '../utils/helpers';
import { COINS } from '../utils/constants';

let livePrices = Object.fromEntries(COINS.map(c => [c.sym, c.basePrice]));

export function getAllPrices() {
  COINS.forEach(c => {
    livePrices[c.sym] *= 1 + (Math.random() - 0.499) * 0.001;
  });
  return { ...livePrices };
}

export function getCoinHistory(sym, timeframe = '1h') {
  const base = livePrices[sym] || 100;
  const countMap    = { '1h': 60, '4h': 48, '1d': 30, '1w': 14 };
  const intervalMap = { '1h': 60, '4h': 240, '1d': 1440, '1w': 10080 };
  return {
    prices: generatePriceData(base, countMap[timeframe] || 60),
    labels: generateTimeLabels(countMap[timeframe] || 60, intervalMap[timeframe] || 60),
    volume: rnd(100, 999).toFixed(0) + 'M',
  };
}

export function findOrCreateCoin(query) {
  const q = query.trim().toUpperCase();
  const found = COINS.find(c => c.sym === q || c.name.toUpperCase().includes(q));
  if (found) return found;
  const newCoin = {
    sym: q.slice(0, 6),
    name: query,
    emoji: '🔮',
    basePrice: rnd(0.001, 500),
    change: rnd(-8, 8),
  };
  COINS.push(newCoin);
  livePrices[newCoin.sym] = newCoin.basePrice;
  return newCoin;
}
